def modified_encode(list):
    result = []
    if not list:
        return result
    current = list[0]
    count = 1
    for i in range(1, len(list)):
        if list[i] == current:
            count += 1
        else:
            result.append([count, current])
            current = list[i]
            count = 1
    result.append([count, current])
    return result
